ALTER TABLE "entitlements" ADD COLUMN "grant_type" character varying(20) NOT NULL DEFAULT 'none', ADD COLUMN "grant_measure" character varying(20) NULL, ADD COLUMN "grant_duration_value" bigint NULL, ADD COLUMN "grant_duration_unit" character varying(10) NULL, ADD COLUMN "grant_quota" numeric(25,15) NULL, ADD COLUMN "parallel" boolean NOT NULL DEFAULT false;
CREATE TABLE "entitlement_grants" ("id" character varying(50) NOT NULL, "tenant_id" character varying(50) NOT NULL, "status" character varying(20) NOT NULL DEFAULT 'published', "created_at" timestamptz NOT NULL, "updated_at" timestamptz NOT NULL, "created_by" character varying NULL, "updated_by" character varying NULL, "environment_id" character varying(50) NULL DEFAULT '', "entitlement_config_id" character varying(50) NOT NULL, "customer_id" character varying(50) NOT NULL, "subscription_id" character varying(50) NOT NULL, "scope_entity_type" character varying(20) NOT NULL DEFAULT 'feature', "scope_entity_id" character varying(50) NOT NULL, "measure" character varying(20) NOT NULL, "quota" numeric(25,15) NOT NULL, "usage" numeric(25,15) NOT NULL, "valid_from" timestamptz NOT NULL, "valid_to" timestamptz NOT NULL, "grant_status" character varying(20) NOT NULL DEFAULT 'active', "last_alert_pct" bigint NULL, "last_alert_at" timestamptz NULL, "last_computed_at" timestamptz NULL, PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "entitlementgrant_entitlement_config_id_customer_id" ON "entitlement_grants" ("entitlement_config_id", "customer_id") WHERE ((grant_status)::text = ANY (ARRAY['active'::text, 'exhausted'::text]));
CREATE INDEX "entitlementgrant_tenant_id_environment_id_customer_id" ON "entitlement_grants" ("tenant_id", "environment_id", "customer_id") WHERE ((grant_status)::text = ANY (ARRAY['active'::text, 'exhausted'::text]));
CREATE INDEX "entitlementgrant_tenant_id_env_7bc49c5b4c1b6a596b5a84b190a89a71" ON "entitlement_grants" ("tenant_id", "environment_id", "customer_id", "scope_entity_type", "scope_entity_id", "valid_from", "valid_to");
